// Auto-converted from Set v3 (n8n 2.15.x SetV2 node crashes at SetV2.node.ts:352)
return [{ json: {
  "workflow": "hive-pipeline-advance",
  "status": "rejected",
  "error": 'Gate result is not PASS (got: ' + ($json.body.gateResult || 'missing') + '). Pipeline cannot advance without a passing gate result.',
  "currentPhase": $json.body.currentPhase || 'unknown',
  "success": false
} }];

const body = $('Webhook Trigger').first().json.body;
const currentPhase = body.currentPhase;

const phaseOrder = [
  'P0', 'P1a', 'P1b', 'P1c', 'P1d', 'P1.5',
  'P2', 'P3', 'P4', 'P5', 'P6', 'P7',
  'P8', 'P9', 'P10'
];

const phaseNames = {
  'P0': 'Intake',
  'P1a': 'Product Research',
  'P1b': 'OST Analysis',
  'P1c': 'Zara Scenarios',
  'P1d': 'Quality Attributes',
  'P1.5': 'UX Design',
  'P2': 'Architecture',
  'P3': 'Team Assembly',
  'P4': 'Task Breakdown',
  'P5': 'Development',
  'P6': 'Feature Complete',
  'P7': 'Production Deploy',
  'P8': 'Monitoring',
  'P9': 'Lessons Learned',
  'P10': 'Rollback & Recovery'
};

const phaseLeads = {
  'P0': 'atlas',
  'P1a': 'vera',
  'P1b': 'remi',
  'P1c': 'zara',
  'P1d': 'nora',
  'P1.5': 'luna',
  'P2': 'neo',
  'P3': 'aria',
  'P4': 'atlas',
  'P5': 'specialist',
  'P6': 'nora',
  'P7': 'max',
  'P8': 'eli',
  'P9': 'nova',
  'P10': 'max'
};

const currentIndex = phaseOrder.indexOf(currentPhase);
let nextPhase = null;
let error = null;

if (currentIndex === -1) {
  error = `Unknown phase: ${currentPhase}`;
} else if (currentIndex >= phaseOrder.length - 1) {
  error = `No phase after ${currentPhase} — project lifecycle complete`;
} else {
  nextPhase = phaseOrder[currentIndex + 1];
}

return [{
  json: {
    projectId: body.projectId,
    currentPhase,
    nextPhase,
    nextPhaseName: nextPhase ? (phaseNames[nextPhase] || nextPhase) : null,
    nextPhaseLead: nextPhase ? (phaseLeads[nextPhase] || 'atlas') : null,
    gateResult: body.gateResult,
    isReworkPhase: ['P5', 'P6', 'P7'].includes(currentPhase),
    error
  }
}];

const data = $input.first().json;
const body = $('Webhook Trigger').first().json.body;
const currentPhase = data.currentPhase;

const reworkTargets = {
  'P5': 'P5',
  'P6': 'P5',
  'P7': 'P6'
};

let rework = false;
let reworkTarget = null;
let reworkReason = null;

if (body.reworkRequired === true || body.failedCriteria) {
  rework = true;
  reworkTarget = reworkTargets[currentPhase] || currentPhase;
  reworkReason = body.reworkReason || `Gate at ${currentPhase} requires rework — routing back to ${reworkTarget}`;
}

const nextPhase = rework ? reworkTarget : data.nextPhase;

return [{
  json: {
    ...data,
    nextPhase,
    nextPhaseName: rework ? `Rework from ${currentPhase}` : data.nextPhaseName,
    rework,
    reworkTarget: rework ? reworkTarget : null,
    reworkReason
  }
}];

