const phaseData = $('Phase Order Map').first().json;
const body = $('Webhook Trigger').first().json.body;
const now = new Date().toISOString();

let rework = phaseData.rework || false;
let reworkReason = phaseData.reworkReason || null;
try {
  const reworkData = $('Evaluate Rework').first().json;
  rework = reworkData.rework || false;
  reworkReason = reworkData.reworkReason || null;
} catch (e) {
  // Evaluate Rework was not in the execution path
}

let ticketsCreated = [];
try {
  const ticketResponse = $('Create Phase Tickets').first().json;
  ticketsCreated.push(ticketResponse.id || ticketResponse.issueId || 'created');
} catch (e) {
  // No ticket response
}
try {
  const notifyResponse = $('Notify Atlas').first().json;
  ticketsCreated.push(notifyResponse.id || notifyResponse.issueId || 'notification-created');
} catch (e) {
  // No notification response
}

return [{
  json: {
    workflow: 'hive-pipeline-advance',
    endpoint: 'pipeline-advance',
    kind: 'deterministic',
    status: phaseData.error ? 'error' : 'completed',
    receivedAt: $('Webhook Trigger').first().json.headers?.['x-request-start'] || now,
    completedAt: now,
    timeoutMs: 30000,
    success: !phaseData.error,
    projectId: phaseData.projectId,
    currentPhase: phaseData.currentPhase,
    newPhase: phaseData.nextPhase,
    newPhaseName: phaseData.nextPhaseName,
    newPhaseLead: phaseData.nextPhaseLead,
    gateResult: phaseData.gateResult,
    ticketsCreated,
    rework,
    reworkReason,
    error: phaseData.error || null
  }
}];
